"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[5570],{5570:e=>{e.exports=JSON.parse('{"37":{"words":[{"spanish":"la inteligencia artificial","english":"artificial intelligence"},{"spanish":"el algoritmo","english":"algorithm"},{"spanish":"el aprendizaje autom\xe1tico","english":"machine learning"},{"spanish":"el modelo generativo","english":"generative model"},{"spanish":"la \xe9tica de la IA","english":"AI ethics"},{"spanish":"el sesgo algor\xedtmico","english":"algorithmic bias"},{"spanish":"la transparencia algor\xedtmica","english":"algorithmic transparency"},{"spanish":"la trazabilidad de decisiones","english":"decision traceability"},{"spanish":"la automatizaci\xf3n","english":"automation"},{"spanish":"la supervisi\xf3n humana","english":"human oversight"},{"spanish":"la privacidad de datos","english":"data privacy"},{"spanish":"el consentimiento informado","english":"informed consent"},{"spanish":"la huella digital","english":"digital footprint"},{"spanish":"el reconocimiento facial","english":"facial recognition"},{"spanish":"la ciberseguridad","english":"cybersecurity"},{"spanish":"la autenticaci\xf3n multifactor","english":"multi-factor authentication"},{"spanish":"el cifrado de extremo a extremo","english":"end-to-end encryption"},{"spanish":"la filtraci\xf3n de datos","english":"data breach"},{"spanish":"la suplantaci\xf3n de identidad","english":"identity theft"},{"spanish":"la contrase\xf1a robusta","english":"strong password"},{"spanish":"el ataque de phishing","english":"phishing attack"},{"spanish":"la copia de seguridad cifrada","english":"encrypted backup"},{"spanish":"el derecho al olvido","english":"right to be forgotten"},{"spanish":"la brecha digital","english":"digital divide"},{"spanish":"el perfilado automatizado","english":"automated profiling"},{"spanish":"la toma de decisiones automatizada","english":"automated decision-making"},{"spanish":"la moderaci\xf3n de contenido","english":"content moderation"},{"spanish":"la vigilancia masiva","english":"mass surveillance"},{"spanish":"la nube p\xfablica","english":"public cloud"},{"spanish":"el centro de datos","english":"data center"},{"spanish":"anonimizar informaci\xf3n","english":"to anonymize information"},{"spanish":"minimizar datos","english":"to minimize data collection"},{"spanish":"auditar un sistema","english":"to audit a system"},{"spanish":"entrenar un modelo","english":"to train a model"},{"spanish":"corregir un sesgo","english":"to correct a bias"},{"spanish":"el acceso desigual a la tecnolog\xeda","english":"unequal access to technology"},{"spanish":"el video manipulado","english":"manipulated video"},{"spanish":"la firma biom\xe9trica","english":"biometric signature"},{"spanish":"la identidad digital","english":"digital identity"},{"spanish":"la alfabetizaci\xf3n digital","english":"digital literacy"},{"spanish":"el c\xf3digo abierto","english":"open source"},{"spanish":"la interoperabilidad","english":"interoperability"},{"spanish":"la actualizaci\xf3n de seguridad","english":"security update"},{"spanish":"el incidente de seguridad","english":"security incident"},{"spanish":"el uso responsable de la IA","english":"responsible use of AI"}],"conversations":[{"id":1,"topic":"Reconocimiento facial en la escuela","dialog":[{"speaker":"Luc\xeda","spanish":"La direcci\xf3n quiere instalar reconocimiento facial en las entradas porque hubo varios robos y dice que as\xed se evitar\xedan accesos no autorizados.","english":"The school administration wants to install facial recognition at the entrances because there were several thefts, and it says this would prevent unauthorized access."},{"speaker":"Marcos","spanish":"Entiendo la preocupaci\xf3n, pero me inquieta que se normalice la vigilancia y que los errores del sistema afecten m\xe1s a algunos alumnos que a otros.","english":"I understand the concern, but I am troubled by the idea of normalizing surveillance and by the possibility that the system\'s errors may affect some students more than others."},{"speaker":"Luc\xeda","spanish":"La directora insiste en que los datos se guardar\xedan solo por poco tiempo y que \xfanicamente se consultar\xedan si ocurriera un incidente.","english":"The principal insists that the data would be stored only briefly and consulted only if an incident occurred."},{"speaker":"Marcos","spanish":"Eso no bastar\xeda si las familias no pudieran negarse o si ninguna auditor\xeda independiente comprobara que el algoritmo no reproduce sesgos ocultos.","english":"That would not be enough if families could not opt out or if no independent audit verified that the algorithm does not reproduce hidden biases."},{"speaker":"Luc\xeda","spanish":"Adem\xe1s, una asociaci\xf3n de derechos digitales advirti\xf3 que, una vez creada la infraestructura, suele ampliarse su uso m\xe1s all\xe1 del objetivo inicial.","english":"Besides, a digital rights group warned that once the infrastructure is in place, its use often expands beyond the initial purpose."},{"speaker":"Marcos","spanish":"Si aun as\xed siguieran adelante, al menos deber\xeda ser un plan limitado, transparente y f\xe1cil de revocar.","english":"If they went ahead anyway, it should at least be a plan that is limited, transparent, and easy to revoke."}],"questions":[{"question":"\xbfQu\xe9 temor principal expresa Marcos sobre el reconocimiento facial?","options":["Que la escuela pierda el control de las llaves del edificio.","Que la vigilancia se normalice y que el sistema perjudique de forma desigual a ciertos alumnos.","Que los estudiantes olviden sus horarios por culpa de la tecnolog\xeda.","Que el proyecto solo funcione durante los fines de semana."],"answer":"Que la vigilancia se normalice y que el sistema perjudique de forma desigual a ciertos alumnos.","answerIndex":1},{"question":"\xbfPor qu\xe9 no le basta a Marcos con que los datos se guarden poco tiempo?","options":["Porque cree que el problema tambi\xe9n incluye el consentimiento y los posibles sesgos del algoritmo.","Porque piensa que los robos nunca ocurrieron realmente.","Porque quiere sustituir el sistema por c\xe1maras ocultas.","Porque le preocupa \xfanicamente el coste el\xe9ctrico de los servidores."],"answer":"Porque cree que el problema tambi\xe9n incluye el consentimiento y los posibles sesgos del algoritmo.","answerIndex":0},{"question":"Si el plan se aplicara de todos modos, \xbfqu\xe9 condiciones considera m\xednimas?","options":["Que solo los profesores puedan entrar en el edificio principal.","Que se ampl\xede su uso a todas las actividades extraescolares sin debate.","Que sea limitado, transparente y revocable.","Que la escuela no informe a las familias hasta el final del curso."],"answer":"Que sea limitado, transparente y revocable.","answerIndex":2}]},{"id":2,"topic":"Ataque de phishing en la empresa","dialog":[{"speaker":"In\xe9s","spanish":"El departamento financiero estuvo a punto de transferir dinero a una cuenta falsa porque lleg\xf3 un correo que imitaba perfectamente a uno de nuestros proveedores.","english":"The finance department was about to transfer money to a fake account because an email arrived that perfectly imitated one of our suppliers."},{"speaker":"Tom\xe1s","spanish":"Menos mal que la autenticaci\xf3n multifactor retras\xf3 el acceso, aunque eso demuestra que el atacante ya ten\xeda suficientes datos como para sonar cre\xedble.","english":"It is a good thing multi-factor authentication slowed things down, although that shows the attacker already had enough data to sound credible."},{"speaker":"In\xe9s","spanish":"Algunos quieren culpar a la becaria que abri\xf3 el mensaje, pero yo creo que el proceso era d\xe9bil, porque acept\xe1bamos cambios de cuenta solo por correo.","english":"Some people want to blame the intern who opened the message, but I think the process was weak because we accepted account changes by email alone."},{"speaker":"Tom\xe1s","spanish":"Estoy de acuerdo; aunque se forme al personal, el sistema seguir\xe1 fallando si no exigimos dos validaciones y un contacto alternativo con el proveedor.","english":"I agree; even if staff are trained, the system will keep failing unless we require two validations and an alternate contact with the supplier."},{"speaker":"In\xe9s","spanish":"Tambi\xe9n habr\xe1 que notificar el incidente y avisar a los clientes cuyos datos podr\xedan haberse visto comprometidos.","english":"We will also have to report the incident and notify the clients whose data may have been compromised."},{"speaker":"Tom\xe1s","spanish":"Si actuamos con transparencia desde el principio, ser\xe1 m\xe1s probable que la confianza pueda recuperarse.","english":"If we act transparently from the start, it is more likely that trust can be rebuilt."}],"questions":[{"question":"\xbfQu\xe9 problema de fondo identifica In\xe9s en la empresa?","options":["Que faltan proveedores en el mercado internacional.","Que el proceso permit\xeda cambiar datos bancarios sin una verificaci\xf3n s\xf3lida.","Que nadie del departamento financiero sabe leer correos electr\xf3nicos.","Que la autenticaci\xf3n multifactor bloquea todas las compras leg\xedtimas."],"answer":"Que el proceso permit\xeda cambiar datos bancarios sin una verificaci\xf3n s\xf3lida.","answerIndex":1},{"question":"Seg\xfan Tom\xe1s, \xbfqu\xe9 har\xeda falta adem\xe1s de formar al personal?","options":["Eliminar la autenticaci\xf3n multifactor para agilizar pagos.","Cerrar el departamento financiero durante una semana.","Exigir dos validaciones y confirmar por otra v\xeda con el proveedor.","Compartir todas las contrase\xf1as con la direcci\xf3n general."],"answer":"Exigir dos validaciones y confirmar por otra v\xeda con el proveedor.","answerIndex":2},{"question":"\xbfPor qu\xe9 consideran importante informar pronto sobre el incidente?","options":["Porque as\xed ser\xe1 m\xe1s f\xe1cil recuperar la confianza afectada.","Porque la ley obliga a borrar todos los correos inmediatamente.","Porque quieren evitar cualquier revisi\xf3n interna del caso.","Porque el proveedor falso puede corregir sus errores t\xe9cnicos."],"answer":"Porque as\xed ser\xe1 m\xe1s f\xe1cil recuperar la confianza afectada.","answerIndex":0}]},{"id":3,"topic":"Automatizaci\xf3n en el hospital","dialog":[{"speaker":"Paula","spanish":"El hospital est\xe1 probando una herramienta de IA que clasifica mensajes no urgentes para que el personal sanitario responda m\xe1s r\xe1pido.","english":"The hospital is testing an AI tool that classifies non-urgent messages so healthcare staff can respond more quickly."},{"speaker":"Ra\xfal","spanish":"Puede ahorrar tiempo, pero me preocupa que los casos ambiguos o los pacientes mayores queden mal clasificados si se conf\xeda demasiado en la automatizaci\xf3n.","english":"It may save time, but I worry that ambiguous cases or older patients may be misclassified if people rely too heavily on automation."},{"speaker":"Paula","spanish":"La empresa proveedora dice que una enfermera revisar\xe1 todo lo que el sistema marque como dudoso antes de enviar una respuesta.","english":"The vendor says a nurse will review everything the system flags as uncertain before any response is sent."},{"speaker":"Ra\xfal","spanish":"Entonces deber\xedan publicarse los criterios y tendr\xeda que existir un recurso sencillo si una respuesta automatizada afectara la atenci\xf3n de alguien.","english":"Then the criteria should be published and there should be a simple appeal process if an automated response affected someone\'s care."},{"speaker":"Paula","spanish":"Adem\xe1s, ser\xeda clave que la comunidad supiera que la herramienta sirve de apoyo y no pretende sustituir el juicio cl\xednico.","english":"It would also be crucial for the community to know that the tool is meant to support care and not replace clinical judgment."},{"speaker":"Ra\xfal","spanish":"Si se desplegara con supervisi\xf3n real y con canales alternativos para quien los necesite, yo no me opondr\xeda.","english":"If it were deployed with real oversight and with alternative channels for those who need them, I would not oppose it."}],"questions":[{"question":"\xbfCu\xe1l es la condici\xf3n principal que plantea Ra\xfal para no oponerse a la herramienta?","options":["Que se use solo en horarios nocturnos y sin supervisi\xf3n.","Que se despliegue con supervisi\xf3n real y v\xedas alternativas de atenci\xf3n.","Que todos los pacientes acepten respuestas autom\xe1ticas obligatorias.","Que la empresa privada gestione directamente las historias cl\xednicas."],"answer":"Que se despliegue con supervisi\xf3n real y v\xedas alternativas de atenci\xf3n.","answerIndex":1},{"question":"\xbfPor qu\xe9 pide Ra\xfal que se publiquen los criterios del sistema?","options":["Porque cree que los pacientes deber\xedan poder entender y cuestionar decisiones automatizadas.","Porque quiere que los m\xe9dicos dejen de responder mensajes.","Porque piensa que la IA no puede clasificar ning\xfan texto en absoluto.","Porque desea que el hospital cambie todos sus servidores por otros nuevos."],"answer":"Porque cree que los pacientes deber\xedan poder entender y cuestionar decisiones automatizadas.","answerIndex":0},{"question":"\xbfC\xf3mo presenta Paula el papel de la IA dentro del hospital?","options":["Como un sustituto total del personal sanitario.","Como una herramienta de apoyo que no reemplaza el criterio cl\xednico.","Como un sistema secreto reservado a la direcci\xf3n.","Como una campa\xf1a temporal de marketing tecnol\xf3gico."],"answer":"Como una herramienta de apoyo que no reemplaza el criterio cl\xednico.","answerIndex":1}]},{"id":4,"topic":"Brecha digital y tareas escolares","dialog":[{"speaker":"Elena","spanish":"La academia quiere ofrecer un asistente de IA para ayudar con los deberes, y algunos profesores creen que podr\xeda mejorar mucho la pr\xe1ctica individual.","english":"The school wants to offer an AI assistant to help with homework, and some teachers believe it could greatly improve individual practice."},{"speaker":"Nicol\xe1s","spanish":"Puede ser \xfatil, pero no todos los hogares tienen internet estable ni adultos que sepan orientar a los estudiantes cuando la herramienta se equivoca.","english":"It can be useful, but not every household has stable internet or adults who know how to guide students when the tool gets something wrong."},{"speaker":"Elena","spanish":"Se ha propuesto prestar dispositivos y ampliar el horario de la biblioteca para que nadie quede fuera por falta de recursos.","english":"There has been a proposal to lend devices and extend library hours so that no one is left out for lack of resources."},{"speaker":"Nicol\xe1s","spanish":"Eso ayudar\xeda, aunque tambi\xe9n habr\xeda que ense\xf1ar a los alumnos a cuestionar las respuestas en vez de copiar lo primero que sugiera el algoritmo.","english":"That would help, although students would also need to be taught to question the answers instead of copying whatever the algorithm suggests first."},{"speaker":"Elena","spanish":"Exacto; si no se combina acceso con alfabetizaci\xf3n digital, la herramienta podr\xeda ampliar la desigualdad en lugar de reducirla.","english":"Exactly; if access is not combined with digital literacy, the tool could widen inequality instead of reducing it."}],"questions":[{"question":"\xbfPor qu\xe9 Nicol\xe1s cree que el asistente no basta por s\xed solo?","options":["Porque quiere que la biblioteca cierre m\xe1s temprano.","Porque teme que el alumnado deje de usar cuadernos impresos.","Porque el acceso desigual y la falta de gu\xeda pueden limitar su utilidad.","Porque piensa que los profesores no deber\xedan usar ninguna tecnolog\xeda."],"answer":"Porque el acceso desigual y la falta de gu\xeda pueden limitar su utilidad.","answerIndex":2},{"question":"\xbfQu\xe9 medida concreta se menciona para evitar que algunos estudiantes queden excluidos?","options":["Cobrar una tarifa extra por el uso del asistente.","Prestar dispositivos y ampliar el horario de la biblioteca.","Restringir la herramienta a quienes tengan mejores notas.","Sustituir todas las clases por tutor\xedas autom\xe1ticas."],"answer":"Prestar dispositivos y ampliar el horario de la biblioteca.","answerIndex":1},{"question":"\xbfQu\xe9 idea resume mejor la conclusi\xf3n de Elena?","options":["La tecnolog\xeda siempre reduce la desigualdad por s\xed misma.","Solo deber\xedan usar la herramienta los estudiantes m\xe1s avanzados.","El acceso debe ir acompa\xf1ado de alfabetizaci\xf3n digital para que el beneficio sea real.","La academia deber\xeda cancelar cualquier innovaci\xf3n futura."],"answer":"El acceso debe ir acompa\xf1ado de alfabetizaci\xf3n digital para que el beneficio sea real.","answerIndex":2}]}],"stories":[{"id":1,"title":"La asistente virtual del museo","sentences":[{"spanish":"Un museo lanz\xf3 una asistente virtual para recomendar recorridos personalizados seg\xfan la edad, el idioma y los intereses declarados por cada visitante.","english":"A museum launched a virtual assistant to recommend personalized tours based on each visitor\'s age, language, and stated interests."},{"spanish":"Al principio, el sistema parec\xeda brillante, pero pronto se vio que ofrec\xeda rutas menos complejas a muchas mujeres j\xf3venes, como si hubiera aprendido un patr\xf3n injusto.","english":"At first the system seemed brilliant, but it soon became clear that it was offering less complex routes to many young women, as if it had learned an unfair pattern."},{"spanish":"Cuando varias gu\xedas pidieron que se revisara el modelo, la empresa admiti\xf3 que lo hab\xeda entrenado con datos antiguos que reflejaban sesgos ya normalizados.","english":"When several guides asked for the model to be reviewed, the company admitted it had trained it on old data that reflected biases already taken for granted."},{"spanish":"Se suspendi\xf3 temporalmente la funci\xf3n mientras se auditaban las recomendaciones y se redise\xf1aban los criterios con mayor transparencia.","english":"The feature was temporarily suspended while the recommendations were audited and the criteria were redesigned with greater transparency."},{"spanish":"Lo interesante fue que nadie quiso renunciar por completo a la herramienta, sino que se exigi\xf3 que funcionara de manera m\xe1s justa y explicable.","english":"The interesting part was that nobody wanted to abandon the tool completely; instead, they demanded that it work in a fairer and more explainable way."},{"spanish":"Meses despu\xe9s, el museo hab\xeda recuperado la confianza del p\xfablico porque demostr\xf3 que corregir un sistema tambi\xe9n forma parte de usar la IA con responsabilidad.","english":"Months later, the museum had regained the public\'s trust because it showed that correcting a system is also part of using AI responsibly."}]},{"id":2,"title":"Despu\xe9s de la filtraci\xf3n","sentences":[{"spanish":"Una empresa peque\xf1a descubri\xf3 que se hab\xedan expuesto datos de clientes despu\xe9s de que un empleado reutilizara una contrase\xf1a en un servicio externo.","english":"A small company discovered that customer data had been exposed after an employee reused a password on an external service."},{"spanish":"Aunque la direcci\xf3n quiso minimizar el problema al principio, el equipo jur\xeddico insisti\xf3 en que se notificara cuanto antes a las personas afectadas.","english":"Although management wanted to downplay the issue at first, the legal team insisted that the affected people be notified as soon as possible."},{"spanish":"Se activaron copias de seguridad cifradas, se revisaron los accesos y se oblig\xf3 a toda la plantilla a usar autenticaci\xf3n multifactor.","english":"Encrypted backups were activated, access was reviewed, and the entire staff was required to use multi-factor authentication."},{"spanish":"Tambi\xe9n se contrat\xf3 una auditor\xeda externa para que quedara claro qu\xe9 fall\xf3 y por qu\xe9 ciertas alertas no se hab\xedan atendido a tiempo.","english":"An external audit was also commissioned so it would be clear what had failed and why certain alerts had not been addressed in time."},{"spanish":"La recuperaci\xf3n fue lenta, pero los clientes valoraron que la empresa hubiera reconocido sus errores en vez de ocultarlos.","english":"The recovery was slow, but customers appreciated that the company had acknowledged its mistakes instead of hiding them."},{"spanish":"A partir de entonces, la seguridad dej\xf3 de verse como un gasto inc\xf3modo y pas\xf3 a entenderse como una condici\xf3n b\xe1sica de la confianza digital.","english":"From then on, security stopped being seen as an annoying expense and came to be understood as a basic condition of digital trust."}]},{"id":3,"title":"El centro comunitario y la brecha digital","sentences":[{"spanish":"En un barrio perif\xe9rico se abri\xf3 un centro comunitario porque muchas familias hab\xedan quedado rezagadas cada vez que los tr\xe1mites y las clases se trasladaban a internet.","english":"A community center opened in an outer neighborhood because many families had fallen behind each time paperwork and classes moved online."},{"spanish":"Al principio, algunos responsables pensaban que bastar\xeda con repartir tabletas, pero los monitores recordaron que el acceso sin formaci\xf3n rara vez resuelve la desigualdad.","english":"At first, some officials thought handing out tablets would be enough, but the instructors pointed out that access without training rarely solves inequality."},{"spanish":"Por eso se organizaron talleres en los que se ense\xf1aba a detectar estafas, proteger la privacidad y cuestionar respuestas generadas por inteligencia artificial.","english":"That is why workshops were organized to teach people how to spot scams, protect privacy, and question answers generated by artificial intelligence."},{"spanish":"Tambi\xe9n se ofreci\xf3 apoyo a quienes nunca hab\xedan creado una cuenta segura o no sab\xedan c\xf3mo activar una copia de seguridad.","english":"Support was also offered to those who had never created a secure account or did not know how to enable a backup."},{"spanish":"Con el tiempo, se vio que la confianza crec\xeda cuando la tecnolog\xeda dejaba de imponerse y empezaba a explicarse con paciencia.","english":"Over time, it became clear that trust grew when technology stopped being imposed and began to be explained patiently."},{"spanish":"El proyecto no elimin\xf3 la brecha digital de un d\xeda para otro, pero s\xed evit\xf3 que la automatizaci\xf3n ampliara una exclusi\xf3n que ya exist\xeda.","english":"The project did not erase the digital divide overnight, but it did prevent automation from widening an exclusion that already existed."}]}],"speaking":{"title":"Hablar sobre IA, privacidad y vida digital","description":"Practica argumentos avanzados sobre automatizaci\xf3n, ciberseguridad, sesgos, consentimiento y riesgos tecnol\xf3gicos.","questions_and_answers":[{"question":{"spanish":"\xbfQu\xe9 ventajas puede aportar la inteligencia artificial en un hospital?","english":"What advantages can artificial intelligence bring to a hospital?"},"answer":{"spanish":"Puede agilizar tareas repetitivas y ayudar a priorizar casos, siempre que haya supervisi\xf3n humana.","english":"It can speed up repetitive tasks and help prioritize cases, as long as there is human oversight."}},{"question":{"spanish":"\xbfQu\xe9 riesgo ves en el reconocimiento facial en espacios p\xfablicos?","english":"What risk do you see in facial recognition in public spaces?"},"answer":{"spanish":"Veo el riesgo de que se normalice la vigilancia y de que se identifique mal a personas inocentes.","english":"I see the risk that surveillance becomes normalized and that innocent people are misidentified."}},{"question":{"spanish":"Si un algoritmo negara un pr\xe9stamo, \xbfqu\xe9 deber\xeda poder hacer el ciudadano?","english":"If an algorithm denied a loan, what should the citizen be able to do?"},"answer":{"spanish":"Deber\xeda poder pedir una explicaci\xf3n clara y solicitar que una persona revise la decisi\xf3n.","english":"They should be able to request a clear explanation and ask for a person to review the decision."}},{"question":{"spanish":"\xbfC\xf3mo proteger\xedas a una empresa contra la suplantaci\xf3n de identidad?","english":"How would you protect a company against identity theft?"},"answer":{"spanish":"Exigir\xeda autenticaci\xf3n multifactor, confirmaciones por otra v\xeda y formaci\xf3n frecuente contra el phishing.","english":"I would require multi-factor authentication, confirmations through another channel, and frequent anti-phishing training."}},{"question":{"spanish":"Explica por qu\xe9 la privacidad de datos no deber\xeda tratarse como un detalle menor.","english":"Explain why data privacy should not be treated as a minor detail."},"answer":{"spanish":"No deber\xeda tratarse como algo secundario porque, si se recopilan demasiados datos, el da\xf1o de una filtraci\xf3n puede ser enorme.","english":"It should not be treated as secondary because if too much data is collected, the damage from a breach can be enormous."}},{"question":{"spanish":"\xbfQu\xe9 tendr\xeda que ocurrir para que confiaras m\xe1s en una herramienta de IA?","english":"What would have to happen for you to trust an AI tool more?"},"answer":{"spanish":"Tendr\xeda que saberse con qu\xe9 datos se entren\xf3, c\xf3mo se audita y qu\xe9 l\xedmites tiene.","english":"It would have to be clear what data it was trained on, how it is audited, and what its limits are."}},{"question":{"spanish":"\xbfQu\xe9 significa tener una huella digital?","english":"What does it mean to have a digital footprint?"},"answer":{"spanish":"Significa dejar rastros de actividad en l\xednea que pueden revelar h\xe1bitos, gustos y relaciones.","english":"It means leaving traces of online activity that can reveal habits, tastes, and relationships."}},{"question":{"spanish":"Di una medida para reducir la brecha digital en tu comunidad.","english":"Give one measure to reduce the digital divide in your community."},"answer":{"spanish":"Ser\xeda \xfatil que se prestaran dispositivos y que hubiera talleres gratuitos de alfabetizaci\xf3n digital.","english":"It would be useful for devices to be lent out and for free digital literacy workshops to be available."}},{"question":{"spanish":"\xbfPor qu\xe9 la automatizaci\xf3n no deber\xeda sustituir siempre a una persona?","english":"Why should automation not always replace a person?"},"answer":{"spanish":"Porque hay decisiones que afectan derechos o contextos complejos y no deber\xedan resolverse sin criterio humano.","english":"Because some decisions affect rights or complex contexts and should not be resolved without human judgment."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si recibieras un mensaje sospechoso de tu banco?","english":"What would you do if you received a suspicious message from your bank?"},"answer":{"spanish":"No abrir\xeda enlaces, comprobar\xeda el remitente y contactar\xeda con el banco por un canal oficial.","english":"I would not open links, I would verify the sender, and I would contact the bank through an official channel."}},{"question":{"spanish":"Usa el condicional para hablar de una ciudad m\xe1s automatizada.","english":"Use the conditional to talk about a more automated city."},"answer":{"spanish":"Una ciudad m\xe1s automatizada podr\xeda ser m\xe1s eficiente, pero tambi\xe9n ser\xeda m\xe1s vulnerable si no protegiera bien los datos.","english":"A more automated city could be more efficient, but it would also be more vulnerable if it did not protect data properly."}},{"question":{"spanish":"\xbfQu\xe9 importancia tiene el consentimiento informado en una app?","english":"How important is informed consent in an app?"},"answer":{"spanish":"Tiene mucha importancia, porque el usuario deber\xeda entender qu\xe9 datos cede y para qu\xe9 se van a usar.","english":"It is very important because the user should understand what data they are giving away and what it will be used for."}},{"question":{"spanish":"Menciona un caso en el que se necesite una auditor\xeda independiente.","english":"Mention a case in which an independent audit is needed."},"answer":{"spanish":"Se necesita cuando un sistema decide sobre empleo, cr\xe9dito o acceso a servicios y podr\xeda reproducir sesgos invisibles.","english":"It is needed when a system decides on employment, credit, or access to services and could reproduce invisible biases."}},{"question":{"spanish":"\xbfQu\xe9 se ha vuelto m\xe1s dif\xedcil desde que circulan videos manipulados?","english":"What has become harder since manipulated videos began circulating?"},"answer":{"spanish":"Se ha vuelto m\xe1s dif\xedcil distinguir r\xe1pidamente entre una prueba real y un montaje convincente.","english":"It has become harder to quickly distinguish between real evidence and a convincing fake."}},{"question":{"spanish":"Explica por qu\xe9 conviene minimizar los datos que una empresa recopila.","english":"Explain why it is wise to minimize the data a company collects."},"answer":{"spanish":"Conviene porque, cuanto menos se almacene, menos informaci\xf3n quedar\xe1 expuesta si ocurre un incidente de seguridad.","english":"It is wise because the less that is stored, the less information will be exposed if a security incident happens."}},{"question":{"spanish":"\xbfQu\xe9 deber\xeda ense\xf1arse a los estudiantes sobre herramientas de IA?","english":"What should students be taught about AI tools?"},"answer":{"spanish":"Deber\xeda ense\xf1\xe1rseles a comprobar fuentes, detectar errores y no confiar ciegamente en una respuesta bien redactada.","english":"They should be taught to check sources, detect errors, and not blindly trust a well-written answer."}},{"question":{"spanish":"Pon un ejemplo de uso responsable de la IA en el trabajo.","english":"Give an example of responsible AI use at work."},"answer":{"spanish":"Un uso responsable ser\xeda resumir documentos con IA, pero revisar despu\xe9s cada dato antes de enviarlo a un cliente.","english":"A responsible use would be summarizing documents with AI, but then checking every fact before sending it to a client."}},{"question":{"spanish":"\xbfQu\xe9 consecuencia puede tener una filtraci\xf3n de datos para una persona?","english":"What consequence can a data breach have for a person?"},"answer":{"spanish":"Puede exponer su identidad digital y facilitar fraudes que no siempre se corrigen r\xe1pidamente.","english":"It can expose their digital identity and make fraud easier, which is not always fixed quickly."}},{"question":{"spanish":"Usa una frase con subjuntivo para recomendar ciberseguridad b\xe1sica.","english":"Use a sentence with the subjunctive to recommend basic cybersecurity."},"answer":{"spanish":"Es recomendable que cada usuario actualice sus dispositivos y cambie contrase\xf1as d\xe9biles antes de que surja un problema.","english":"It is advisable for every user to update their devices and change weak passwords before a problem arises."}},{"question":{"spanish":"Resume el dilema \xe9tico principal de la inteligencia artificial actual.","english":"Summarize the main ethical dilemma of today\'s artificial intelligence."},"answer":{"spanish":"El dilema principal es c\xf3mo aprovechar su eficacia sin permitir que opaque derechos, responsabilidades y desigualdades ya existentes.","english":"The main dilemma is how to benefit from its efficiency without letting it overshadow rights, responsibilities, and inequalities that already exist."}}]}}}')}}]);